const task = $input.first().json;
const priority = task.priority || 'normal';
const type = task.task || 'unknown';

// AI routing decision
const routes = {
  'analyze_github_trending': ['fetch-github', 'ai-analyze', 'format-report'],
  'code_review': ['clone-repo', 'ai-review', 'post-comment'],
  'web_scrape': ['fetch-page', 'extract-data', 'save-to-db'],
  'send_digest': ['aggregate-data', 'ai-summarize', 'send-email']
};

return {
  taskId: task.task_id || Date.now().toString(),
  type,
  priority,
  steps: routes[type] || ['generic-step'],
  inputParams: task.params || {}
};

const steps = $node['AI Intent Router'].json.steps;
const results = [];

// Fan-out: execute steps in parallel (simulated)
for (const step of steps) {
  results.push({
    step,
    status: 'pending',
    startTime: new Date().toISOString()
  });
}
return results;

// Step executor with retry logic
const item = $input.first().json;
const maxRetries = 3;

// Simulate step execution
const stepResults = {
  'fetch-github': { data: { repos: ['repo1', 'repo2'] } },
  'ai-analyze': { data: { summary: 'AI summary here' } },
  'format-report': { data: { markdown: '# Daily Report' } },
  'clone-repo': { data: { success: true } },
  'ai-review': { data: { comments: [] } },
  'post-comment': { data: { posted: true } },
  'fetch-page': { data: { html: '<html/>' } },
  'extract-data': { data: { items: [] } },
  'save-to-db': { data: { saved: 10 } },
  'aggregate-data': { data: { aggregated: true } },
  'ai-summarize': { data: { summary: 'Digest ready' } },
  'send-email': { data: { sent: true } },
  'generic-step': { data: { done: true } }
};

const result = stepResults[item.step] || { data: { done: true } };
return { ...item, ...result, status: 'completed', endTime: new Date().toISOString() };

// Merge all step results
const allResults = $input.all();
const taskId = $node['AI Intent Router'].json.taskId;

const successful = allResults.filter(r => r.json.status === 'completed');
const failed = allResults.filter(r => r.json.status === 'failed');

return {
  workflowId: taskId,
  totalSteps: allResults.length,
  completed: successful.length,
  failed: failed.length,
  results: allResults.map(r => ({ step: r.json.step, status: r.json.status, data: r.json.data })),
  summary: failed.length > 0 ? 'PARTIAL' : 'SUCCESS',
  timestamp: new Date().toISOString()
};
